mapper.insert:
INSERT INTO t_owners_assembly_session (
    tenant_id, title, preparation_mode, status, created_by_user_id
) VALUES (
    #{tenantId}, #{title}, #{preparationMode}, #{status}, #{createdByUserId}
)

mapper.select:
SELECT session_id, tenant_id, title, preparation_mode, status, created_by_user_id, create_time
FROM t_owners_assembly_session
WHERE session_id = #{sessionId}
  AND tenant_id = #{tenantId}

mapper.insert:
INSERT INTO t_owners_assembly_package (
    session_id, tenant_id, package_version, status, voting_channel_policy,
    public_notice_days, announcement_hash, attachment_manifest_hash,
    ballot_template_hash, electronic_seal_hash, vote_start_at, vote_end_at
) VALUES (
    #{sessionId}, #{tenantId}, #{packageVersion}, #{status}, #{votingChannelPolicy},
    #{publicNoticeDays}, #{announcementHash}, #{attachmentManifestHash},
    #{ballotTemplateHash}, #{electronicSealHash}, #{voteStartAt}, #{voteEndAt}
)

mapper.select:
SELECT *
FROM t_owners_assembly_package
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}

SELECT *
FROM t_owners_assembly_package
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
FOR UPDATE

SELECT subject_id
FROM t_owners_assembly_subject
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
ORDER BY assembly_subject_id

mapper.update:
UPDATE t_owners_assembly_package
SET status = 'VOTING',
    update_time = CURRENT_TIMESTAMP
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND status = 'PUBLIC_NOTICE'

UPDATE t_owners_assembly_package
SET status = 'SETTLED',
    update_time = CURRENT_TIMESTAMP
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND status = 'VOTING'

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM t_owners_assembly_delivery
    WHERE package_id = #{packageId}
      AND tenant_id = #{tenantId}
      AND opid = #{opid}
      AND uid = #{uid}
      AND delivery_channel = #{deliveryChannel}
)

mapper.insert:
INSERT INTO t_owners_assembly_vote_record (
    package_id, subject_id, vote_id, tenant_id, opid, uid, vote_channel,
    package_hash, ballot_file_hash, signature_hash, valid_flag
) VALUES (
    #{packageId}, #{subjectId}, #{voteId}, #{tenantId}, #{opid}, #{uid}, #{voteChannel},
    #{packageHash}, #{ballotFileHash}, #{signatureHash}, #{validFlag}
)

mapper.update:
UPDATE t_owners_assembly_vote_record
SET valid_flag = 0,
    invalidated_by_vote_id = #{invalidatedByVoteId},
    invalid_reason = #{invalidReason}
WHERE vote_id = #{voteId}
  AND valid_flag = 1

mapper.select:
SELECT NOT EXISTS (
    SELECT 1
    FROM t_owners_assembly_subject s
    LEFT JOIN t_voting_result r ON r.subject_id = s.subject_id
    WHERE s.package_id = #{packageId}
      AND s.tenant_id = #{tenantId}
      AND COALESCE(r.passed, 0) != 1
)
